// Core device abstractions
export { Device } from './Device.js';
export type { DeviceCapabilities, DeviceEvent } from './Device.js';
export { DeviceManager } from './DeviceManager.js';
export type { DeviceManagerOptions, DeviceType } from './DeviceManager.js';

// Input devices
export { KeyboardDevice } from './KeyboardDevice.js';
export type { KeyboardEventData } from './KeyboardDevice.js';
export { MouseDevice } from './MouseDevice.js';
export type { MouseEventData } from './MouseDevice.js';
export { TouchDevice } from './TouchDevice.js';
export type {
  TouchEventData,
  TouchPoint,
  OrientationEventData,
} from './TouchDevice.js';

// Audio/video devices
export { AudioDevice } from './AudioDevice.js';
export type { AudioDeviceInfo, AudioEventData } from './AudioDevice.js';
export { VideoDevice } from './VideoDevice.js';
export type { VideoDeviceInfo, VideoEventData } from './VideoDevice.js';

// Import types for internal use
import { Device } from './Device.js';
import { DeviceManager, DeviceManagerOptions } from './DeviceManager.js';
import { KeyboardDevice } from './KeyboardDevice.js';
import { MouseDevice } from './MouseDevice.js';
import { TouchDevice } from './TouchDevice.js';
import { AudioDevice } from './AudioDevice.js';
import { VideoDevice } from './VideoDevice.js';

// Helper functions for common device management patterns
export function createDeviceManager(
  clock: import('@psyforge/timing').PrecisionClock,
  options?: DeviceManagerOptions,
): DeviceManager {
  return new DeviceManager(clock, options);
}

export async function detectDeviceCapabilities(
  clock: import('@psyforge/timing').PrecisionClock,
): Promise<{
  keyboard: boolean;
  mouse: boolean;
  touch: boolean;
  audio: boolean;
  video: boolean;
}> {
  const manager = createDeviceManager(clock, { enableAutoDetection: false });
  return await manager.detectAvailableDevices();
}

// Type guards for device instances
export function isKeyboardDevice(device: Device): device is KeyboardDevice {
  return device.deviceType === 'keyboard';
}

export function isMouseDevice(device: Device): device is MouseDevice {
  return device.deviceType === 'mouse';
}

export function isTouchDevice(device: Device): device is TouchDevice {
  return device.deviceType === 'touch';
}

export function isAudioDevice(device: Device): device is AudioDevice {
  return device.deviceType === 'audio';
}

export function isVideoDevice(device: Device): device is VideoDevice {
  return device.deviceType === 'video';
}

