    if (!this.clock.isHighPrecisionAvailable()) {
      await this.clock.initialize();
    }

    // Start drift monitoring if enabled
    if (fullConfig.enableDriftDetection) {
      this.driftDetector.startMonitoring();
    }

    try {
      // Run individual benchmark tests
      await this.runStimulusOnsetBenchmark(fullConfig);
      await this.runFrameTimingBenchmark(fullConfig);
      await this.runSchedulingPrecisionBenchmark(fullConfig);
      await this.runResponseTimingBenchmark(fullConfig);

      // Generate summary report
      this.generateBenchmarkReport();

      return this.results;
    } finally {
      // Clean up
      if (fullConfig.enableDriftDetection) {
        this.driftDetector.stopMonitoring();
      }
    }
  }

  /**
   * Test stimulus onset timing accuracy
   */
  private async runStimulusOnsetBenchmark(config: BenchmarkConfig): Promise<void> {
    const testName = 'Stimulus Onset Accuracy';
    const latencies: number[] = [];
    const frameDrops = 0;

    // Warmup
    for (let i = 0; i < config.warmupIterations; i++) {
      await this.measureStimulusOnset();
    }

    // Actual measurements
    const startTime = Date.now();
    for (let i = 0; i < config.iterations; i++) {
      const latency = await this.measureStimulusOnset();
      latencies.push(latency);

      // Small delay between measurements
      await new Promise(resolve => setTimeout(resolve, 10));
    }
    const duration = Date.now() - startTime;

    const result = this.calculateBenchmarkResults(
      testName,
      duration,
      latencies,
      frameDrops,
      config.targetAccuracy
    );

    this.results.push(result);
  }

  /**
   * Test RequestAnimationFrame timing consistency
   */
  private async runFrameTimingBenchmark(config: BenchmarkConfig): Promise<void> {
    const testName = 'Frame Timing Consistency';
    const frameTimings: number[] = [];
    let frameDrops = 0;
    let lastFrameTime = 0;

    const frameCallback = (timestamp: number) => {
      if (lastFrameTime > 0) {
        const frameDelta = timestamp - lastFrameTime;
        frameTimings.push(frameDelta);

        // Detect frame drops (assuming 60Hz display)
        if (frameDelta > 20) { // >20ms indicates dropped frame
          frameDrops++;
        }
      }
      lastFrameTime = timestamp;
    };

    const unsubscribe = this.clock.onFrame(frameCallback);

    // Run for specified duration
    await new Promise(resolve => 
      setTimeout(resolve, config.testDuration * 1000)
    );

    unsubscribe();

    const result = this.calculateBenchmarkResults(
      testName,
      config.testDuration * 1000,
      frameTimings,
      frameDrops,
      config.targetAccuracy
    );

    this.results.push(result);
  }

  /**
   * Test scheduling precision for timed callbacks
   */
  private async runSchedulingPrecisionBenchmark(config: BenchmarkConfig): Promise<void> {
    const testName = 'Scheduling Precision';
    const schedulingErrors: number[] = [];

    for (let i = 0; i < config.iterations; i++) {
      const targetDelay = 50 + (i % 100); // Variable delays 50-150ms
      const error = await this.measureSchedulingPrecision(targetDelay);
      schedulingErrors.push(Math.abs(error));
    }

    const result = this.calculateBenchmarkResults(
      testName,
      config.iterations * 100, // Estimated duration
      schedulingErrors,
      0,
      config.targetAccuracy
    );

    this.results.push(result);
  }

  /**
   * Test response timing measurement accuracy
   */
  private async runResponseTimingBenchmark(config: BenchmarkConfig): Promise<void> {
    const testName = 'Response Timing Accuracy';
    const responseTimes: number[] = [];

    for (let i = 0; i < Math.min(config.iterations, 100); i++) {
      const responseTime = await this.measureResponseTiming();
      responseTimes.push(responseTime);
    }

    const result = this.calculateBenchmarkResults(
      testName,
      responseTimes.length * 50, // Estimated duration
      responseTimes,
      0,
      config.targetAccuracy
    );

    this.results.push(result);
  }

  /**
   * Measure stimulus onset latency
   */
  private async measureStimulusOnset(): Promise<number> {
    const start = this.clock.now();

    // Simulate stimulus presentation
    await new Promise(resolve => requestAnimationFrame(() => resolve(undefined)));

    const end = this.clock.now();
    return end.performanceTime - start.performanceTime;
  }

  /**
   * Measure scheduling precision
   */
  private async measureSchedulingPrecision(targetDelay: number): Promise<number> {
    return new Promise((resolve) => {
      const start = this.clock.now();
      const targetTime = start.audioTime + (targetDelay / 1000);

      this.clock.scheduleCallback(targetTime, () => {
        const actual = this.clock.now();
        const actualDelay = (actual.audioTime - start.audioTime) * 1000;
        resolve(actualDelay - targetDelay);
      });
    });
  }

  /**
   * Simulate response timing measurement
   */
  private async measureResponseTiming(): Promise<number> {
    const start = this.clock.now();

    // Simulate random response delay
    const delay = 100 + Math.random() * 200;
    await new Promise(resolve => setTimeout(resolve, delay));

    const end = this.clock.now();
    return end.performanceTime - start.performanceTime;
  }

  /**
   * Calculate benchmark results from latency measurements
   */
  private calculateBenchmarkResults(
    testName: string,
    duration: number,
    latencies: number[],
    frameDrops: number,
    targetAccuracy: number
  ): BenchmarkResults {
    if (latencies.length === 0) {
      throw new Error(`No measurements collected for test: ${testName}`);
    }

    const sortedLatencies = [...latencies].sort((a, b) => a - b);
    const minLatency = sortedLatencies[0]!;
    const maxLatency = sortedLatencies[sortedLatencies.length - 1]!;
    const averageLatency = latencies.reduce((a, b) => a + b, 0) / latencies.length;

    const p95Index = Math.floor(sortedLatencies.length * 0.95);
    const p99Index = Math.floor(sortedLatencies.length * 0.99);
    const p95Latency = sortedLatencies[p95Index] || maxLatency;
    const p99Latency = sortedLatencies[p99Index] || maxLatency;

    const stimulusOnsetAccuracy = p95Latency; // Use P95 as accuracy metric
    const passed = stimulusOnsetAccuracy <= targetAccuracy;

    const warnings: string[] = [];
    if (!passed) {
      warnings.push(`Target accuracy of ${targetAccuracy}ms not met (actual: ${stimulusOnsetAccuracy.toFixed(2)}ms)`);
    }
    if (frameDrops > 0) {
      warnings.push(`${frameDrops} frame drops detected`);
    }

    const hardwareCapabilities = this.assessHardwareCapabilities();
    const driftStatus = this.driftDetector.getDriftStatus();

    return {
      testName,
      duration,
      iterations: latencies.length,
      minLatency,
      maxLatency,
      averageLatency,
      p95Latency,
      p99Latency,
      stimulusOnsetAccuracy,
      frameDrops,
      driftStatus,
      hardwareCapabilities,
      passed,
      warnings
    };
  }

  /**
   * Assess hardware timing capabilities
   */
  private assessHardwareCapabilities(): HardwareCapabilities {
    const audioContext = (this.clock as any).audioContext;

    return {
      audioContextSampleRate: audioContext?.sampleRate || 0,
      displayRefreshRate: this.estimateDisplayRefreshRate(),
      performanceTimerResolution: this.clock.getPrecisionEstimate(),
      highPrecisionAvailable: this.clock.isHighPrecisionAvailable(),
      webAudioSupported: !!audioContext,
      rafSupported: typeof requestAnimationFrame !== 'undefined'
    };
  }

  /**
   * Estimate display refresh rate
   */
  private estimateDisplayRefreshRate(): number {
    // Simple estimate - could be improved with more sophisticated detection
    return 60; // Default assumption
  }

  /**
   * Generate comprehensive benchmark report
   */
  private generateBenchmarkReport(): void {
    const allPassed = this.results.every(r => r.passed);
    const overallAccuracy = Math.max(...this.results.map(r => r.stimulusOnsetAccuracy));

    console.log('\n=== Psycho-Forge Timing Benchmark Report ===');
    console.log(`Overall Status: ${allPassed ? 'PASS' : 'FAIL'}`);
    console.log(`Best Stimulus Onset Accuracy: ${overallAccuracy.toFixed(2)}ms`);
    console.log(`Target Accuracy: ≤2ms`);
    console.log('\nIndividual Test Results:');

    this.results.forEach(result => {
      console.log(`\n${result.testName}: ${result.passed ? 'PASS' : 'FAIL'}`);
      console.log(`  Accuracy: ${result.stimulusOnsetAccuracy.toFixed(2)}ms`);
      console.log(`  P95 Latency: ${result.p95Latency.toFixed(2)}ms`);
      console.log(`  Iterations: ${result.iterations}`);

      if (result.warnings.length > 0) {
        console.log(`  Warnings: ${result.warnings.join(', ')}`);
      }
    });

    // Hardware capabilities summary
    const hw = this.results[0]?.hardwareCapabilities;
    if (hw) {
      console.log('\nHardware Capabilities:');
      console.log(`  Audio Sample Rate: ${hw.audioContextSampleRate}Hz`);
      console.log(`  Display Refresh Rate: ${hw.displayRefreshRate}Hz`);
      console.log(`  Timer Resolution: ${hw.performanceTimerResolution.toFixed(1)}μs`);
      console.log(`  High Precision Available: ${hw.highPrecisionAvailable}`);
    }
  }

  /**
   * Export results for publication/validation
   */
  exportResults(): string {
    return JSON.stringify({
      timestamp: new Date().toISOString(),
      version: '1.0.0',
      results: this.results,
      summary: {
        allTestsPassed: this.results.every(r => r.passed),
        overallAccuracy: Math.max(...this.results.map(r => r.stimulusOnsetAccuracy)),
        targetMet: Math.max(...this.results.map(r => r.stimulusOnsetAccuracy)) <= 2
      }
    }, null, 2);
  }
}

/**
 * Create a timing benchmark harness
 */
export function createTimingBenchmark(clock: PrecisionClock): TimingBenchmarkHarness {
  return new TimingBenchmarkHarness(clock);
}

