/**
 * Timing Benchmark Harness v1
 * Comprehensive timing validation tools to verify precision capabilities
 */

import { PrecisionClock } from './PrecisionClock';
import { TimingDriftDetector, DriftStatus } from './TimingDriftDetector';

export interface BenchmarkResults {
  readonly testName: string;
  readonly duration: number;
  readonly iterations: number;
  readonly minLatency: number;
  readonly maxLatency: number;
  readonly averageLatency: number;
  readonly p95Latency: number;
  readonly p99Latency: number;
  readonly stimulusOnsetAccuracy: number;
  readonly frameDrops: number;
  readonly driftStatus: DriftStatus;
  readonly hardwareCapabilities: HardwareCapabilities;
  readonly passed: boolean;
  readonly warnings: string[];
}

export interface HardwareCapabilities {
  readonly audioContextSampleRate: number;
  readonly displayRefreshRate: number;
  readonly performanceTimerResolution: number;
  readonly highPrecisionAvailable: boolean;
  readonly webAudioSupported: boolean;
  readonly rafSupported: boolean;
}

export interface BenchmarkConfig {
  readonly iterations: number;
  readonly targetAccuracy: number; // milliseconds
  readonly testDuration: number; // seconds
  readonly warmupIterations: number;
  readonly enableDriftDetection: boolean;
  readonly enableExternalValidation: boolean;
}

export class TimingBenchmarkHarness {
  private clock: PrecisionClock;
  private driftDetector: TimingDriftDetector;
  private results: BenchmarkResults[] = [];

  constructor(clock: PrecisionClock) {
    this.clock = clock;

